  1→import type { CreateWorkspaceRequest, OnboardingAction } from "../../shared/contracts";
  2→import { HttpError } from "./errors";
  3→
  4→const MAX_UPLOAD_BYTES = 2 * 1024 * 1024;
  5→const allowedUploadExtensions = new Set(["md", "txt"]);
  6→
  7→export type IncomingAttachment = {
  8→  fileName: string;
  9→  mimeType: string;
 10→  sizeBytes: number;
 11→  content: string;
 12→};
 13→
 14→export type ParsedIncomingMessage = {
 15→  clientMessageId: string;
 16→  workspaceId: string;
 17→  conversationId?: string;
 18→  text: string;
 19→  onboardingAction?: OnboardingAction;
 20→  attachment?: IncomingAttachment;
 21→  discussEntityId?: string;
 22→};
 23→
 24→const onboardingActions = new Set(["finalize_onboarding", "continue_onboarding"]);
 25→
 26→export function parseCreateWorkspaceRequest(body: unknown):
 27→  | { ok: true; data: CreateWorkspaceRequest }
 28→  | { ok: false; error: string } {
 29→  if (!body || typeof body !== "object") {
 30→    return { ok: false, error: "Body must be an object" };
 31→  }
 32→
 33→  const payload = body as Partial<CreateWorkspaceRequest>;
 34→
 35→  if (!payload.name || payload.name.trim().length === 0) {
 36→    return { ok: false, error: "name is required" };
 37→  }
 38→
 39→  if (!payload.ownerDisplayName || payload.ownerDisplayName.trim().length === 0) {
 40→    return { ok: false, error: "ownerDisplayName is required" };
 41→  }
 42→
 43→  if (!payload.ownerEmail || payload.ownerEmail.trim().length === 0) {
 44→    return { ok: false, error: "ownerEmail is required" };
 45→  }
 46→
 47→  const description = typeof payload.description === "string" ? payload.description.trim() : undefined;
 48→
 49→  return {
 50→    ok: true,
 51→    data: {
 52→      name: payload.name.trim(),
 53→      ownerDisplayName: payload.ownerDisplayName.trim(),
 54→      ownerEmail: payload.ownerEmail.trim(),
 55→      ...(description && description.length > 0 ? { description } : {}),
 56→    },
 57→  };
 58→}
 59→
 60→export async function parseIncomingMessageRequest(
 61→  request: Request,
 62→): Promise<{ ok: true; data: ParsedIncomingMessage } | { ok: false; error: string }> {
 63→  const contentType = request.headers.get("content-type") ?? "";
 64→
 65→  if (contentType.includes("multipart/form-data")) {
 66→    const formData = await request.formData();
 67→
 68→    const clientMessageIdValue = formData.get("clientMessageId");
 69→    const workspaceIdValue = formData.get("workspaceId");
 70→    const conversationIdValue = formData.get("conversationId");
 71→    const textValue = formData.get("text");
 72→    const onboardingActionValue = formData.get("onboardingAction");
 73→    const discussEntityIdValue = formData.get("discussEntityId");
 74→
 75→    if (typeof clientMessageIdValue !== "string" || clientMessageIdValue.trim().length === 0) {
 76→      return { ok: false, error: "clientMessageId is required" };
 77→    }
 78→
 79→    if (typeof workspaceIdValue !== "string" || workspaceIdValue.trim().length === 0) {
 80→      return { ok: false, error: "workspaceId is required" };
 81→    }
 82→
 83→    const text = typeof textValue === "string" ? textValue.trim() : "";
 84→
 85→    const fileValue = formData.get("file");
 86→    let attachment: IncomingAttachment | undefined;
 87→    if (fileValue instanceof File) {
 88→      try {
 89→        attachment = await parseIncomingAttachment(fileValue);
 90→      } catch (error) {
 91→        if (error instanceof HttpError) {
 92→          return { ok: false, error: error.message };
 93→        }
 94→        throw error;
 95→      }
 96→    }
 97→
 98→    if (!attachment && text.length === 0) {
 99→      return { ok: false, error: "text is required when no file is uploaded" };
100→    }
101→
102→    const conversationId =
103→      typeof conversationIdValue === "string" && conversationIdValue.trim().length > 0
104→        ? conversationIdValue.trim()
105→        : undefined;
106→    const onboardingAction = typeof onboardingActionValue === "string" && onboardingActionValue.trim().length > 0
107→      ? onboardingActionValue.trim()
108→      : undefined;
109→    if (onboardingAction && !onboardingActions.has(onboardingAction)) {
110→      return { ok: false, error: "onboardingAction must be finalize_onboarding or continue_onboarding" };
111→    }
112→
113→    const discussEntityId =
114→      typeof discussEntityIdValue === "string" && discussEntityIdValue.trim().length > 0
115→        ? discussEntityIdValue.trim()
116→        : undefined;
117→
118→    return {
119→      ok: true,
120→      data: {
