 53→    handleWorkspaceBootstrap: (workspaceId: string) => handleWorkspaceBootstrap(deps, workspaceId),
 54→    handleWorkspaceSidebar: (workspaceId: string) => handleWorkspaceSidebar(deps, workspaceId),
 55→    handleWorkspaceConversation: (workspaceId: string, conversationId: string) =>
 56→      handleWorkspaceConversation(deps, workspaceId, conversationId),
 57→  };
 58→}
