255→async function resolveWorkspaceBootstrapConversation(
256→  deps: ServerDependencies,
257→  workspaceRecord: RecordId<"workspace", string>,
258→): Promise<RecordId<"conversation", string>> {
259→  const [onboardingRows] = await deps.surreal
260→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
261→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace AND source = 'onboarding' ORDER BY createdAt ASC LIMIT 1;",
262→      {
263→        workspace: workspaceRecord,
264→      },
265→    )
266→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
267→
268→  if (onboardingRows.length > 0) {
269→    return onboardingRows[0].id;
270→  }
271→
272→  const [latestRows] = await deps.surreal
273→    .query<[Array<{ id: RecordId<"conversation", string> }>]>(
274→      "SELECT id, createdAt FROM conversation WHERE workspace = $workspace ORDER BY createdAt DESC LIMIT 1;",
275→      {
276→        workspace: workspaceRecord,
277→      },
278→    )
279→    .collect<[Array<{ id: RecordId<"conversation", string> }>]>();
280→
281→  if (latestRows.length > 0) {
282→    return latestRows[0].id;
283→  }
284→
285→  const now = new Date();
286→  const conversationRecord = new RecordId("conversation", randomUUID());
287→  await deps.surreal.create(conversationRecord).content({
288→    createdAt: now,
289→    updatedAt: now,
290→    workspace: workspaceRecord,
291→    source: "onboarding",
292→  });
293→  return conversationRecord;
294→}
