296→async function loadWorkspaceSeeds(
297→  deps: ServerDependencies,
298→  workspaceRecord: RecordId<"workspace", string>,
299→  limit: number,
300→): Promise<OnboardingSeedItem[]> {
301→  const [edgeRows] = await deps.surreal
302→    .query<[ProvenanceEdgeRow[]]>(
303→      [
304→        "SELECT id, `in`, out, confidence, extracted_at",
305→        "FROM extraction_relation",
306→        "WHERE `in` IN array::concat(",
307→        "  (SELECT VALUE id FROM message WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)),",
308→        "  (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
309→        ")",
310→        "ORDER BY extracted_at DESC",
311→        "LIMIT $limit;",
312→      ].join(" "),
313→      {
314→        workspace: workspaceRecord,
315→        limit,
316→      },
317→    )
318→    .collect<[ProvenanceEdgeRow[]]>();
319→
320→  const items: OnboardingSeedItem[] = [];
321→
322→  for (const edge of edgeRows) {
323→    const entityText = await readEntityText(deps.surreal, edge.out);
324→    if (!entityText) {
325→      continue;
326→    }
327→
328→    const sourceTable = edge.in.table.name;
329→    const entityTable = edge.out.table.name;
330→    const sourceKind = (sourceTable === "document_chunk" ? "document_chunk" : "message") as SourceKind;
331→    const sourceLabel = await readSourceLabel(deps, edge.in);
332→
333→    items.push({
334→      id: edge.out.id as string,
335→      kind: entityTable as EntityKind,
336→      text: entityText,
337→      confidence: edge.confidence,
338→      sourceKind,
339→      sourceId: edge.in.id as string,
340→      ...(sourceLabel ? { sourceLabel } : {}),
341→    });
342→  }
343→
344→  return items;
345→}
346→
347→async function readSourceLabel(deps: ServerDependencies, sourceRecord: SourceRecord): Promise<string | undefined> {
348→  const sourceTable = sourceRecord.table.name;
349→  if (sourceTable === "message") {
350→    const row = await deps.surreal.select<{ text: string }>(sourceRecord);
351→    if (!row) {
352→      return undefined;
353→    }
354→    return row.text.slice(0, 140);
355→  }
356→
357→  const chunk = await deps.surreal.select<{
358→    section_heading?: string;
359→    document: RecordId<"document", string>;
360→  }>(sourceRecord);
361→
362→  if (!chunk) {
363→    return undefined;
364→  }
365→
366→  const document = await deps.surreal.select<{ name: string }>(chunk.document);
367→  if (!document) {
368→    return chunk.section_heading;
369→  }
370→
371→  if (chunk.section_heading) {
372→    return `${document.name} · ${chunk.section_heading}`;
373→  }
374→
375→  return document.name;
376→}
