 15→function AppShell() {
 16→  const workspace = useWorkspace();
 17→  const sidebar = useWorkspaceState((s) => s.sidebar);
 18→  const sidebarHandlers = useWorkspaceState((s) => s.sidebarHandlers);
 19→  const workspaceName = useWorkspaceState((s) => s.workspaceName);
 20→  const onboardingState = useWorkspaceState((s) => s.onboardingState);
 21→  const navigate = useNavigate();
 22→  const [searchOpen, setSearchOpen] = useState(false);
 23→
 24→  function handleNewConversation() {
 25→    if (sidebarHandlers) {
 26→      sidebarHandlers.onNewConversation();
 27→    }
 28→    void navigate({ to: "/chat" });
 29→  }
 30→
 31→  function handleSelectConversation(conversationId: string) {
 32→    if (sidebarHandlers) {
 33→      sidebarHandlers.onSelectConversation(conversationId);
 34→    }
