 1→import { describe, expect, it } from "bun:test";
 2→import { randomUUID } from "node:crypto";
 3→import { collectSseEvents, fetchJson, setupSmokeSuite } from "./smoke-test-kit";
 4→
 5→type ChatMessageResponse = {
 6→  messageId: string;
 7→  userMessageId: string;
 8→  conversationId: string;
 9→  workspaceId: string;
10→  streamUrl: string;
11→};
12→
13→type StreamEvent =
14→  | { type: "token"; messageId: string; token: string }
15→  | { type: "assistant_message"; messageId: string; text: string }
16→  | {
17→      type: "extraction";
18→      messageId: string;
19→      entities: Array<{ id: string; kind: string; text: string }>;
20→      relationships: Array<{ id: string; kind: string }>;
21→    }
22→  | { type: "done"; messageId: string }
23→  | { type: "error"; messageId: string; error: string }
24→  | { type: string; messageId: string };
25→
26→const getRuntime = setupSmokeSuite("phase1");
27→
28→describe("phase1 smoke", () => {
29→  it("chat pipeline streams tokens, extraction, and assistant message", async () => {
30→    const { baseUrl } = getRuntime();
31→
32→    const health = await fetchJson<{ status: string }>(`${baseUrl}/healthz`);
33→    expect(health.status).toBe("ok");
34→
35→    const workspace = await fetchJson<{ workspaceId: string; conversationId: string }>(`${baseUrl}/api/workspaces`, {
36→      method: "POST",
37→      headers: { "Content-Type": "application/json" },
38→      body: JSON.stringify({
39→        name: `Phase1 Smoke ${Date.now()}`,
40→        ownerDisplayName: "Marcus", ownerEmail: `${Date.now()}-1@smoke.test`,
41→      }),
42→    });
43→
44→    const chatResponse = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
45→      method: "POST",
46→      headers: { "Content-Type": "application/json" },
47→      body: JSON.stringify({
48→        clientMessageId: randomUUID(),
49→        workspaceId: workspace.workspaceId,
50→        conversationId: workspace.conversationId,
51→        text: "We need to ship an OAuth callback handler this week and decide on OpenRouter embeddings vs a fallback provider.",
52→      }),
53→    });
54→
55→    expect(chatResponse.messageId.length).toBeGreaterThan(0);
56→    expect(chatResponse.userMessageId.length).toBeGreaterThan(0);
57→    expect(chatResponse.conversationId).toBe(workspace.conversationId);
58→    expect(chatResponse.workspaceId).toBe(workspace.workspaceId);
59→    expect(chatResponse.streamUrl.length).toBeGreaterThan(0);
60→
61→    const events = await collectSseEvents<StreamEvent>(`${baseUrl}${chatResponse.streamUrl}`, 120_000);
62→    const eventTypes = events.map((event) => event.type);
63→
64→    // Core SSE pipeline: tokens stream, extraction event fires, assistant responds, done signals completion
65→    expect(eventTypes.includes("token")).toBe(true);
66→    expect(eventTypes.includes("extraction")).toBe(true);
67→    expect(eventTypes.includes("assistant_message")).toBe(true);
68→    expect(eventTypes[eventTypes.length - 1]).toBe("done");
69→
70→    // Assistant should provide a meaningful response
71→    const assistantEvent = events.find((event) => event.type === "assistant_message");
72→    if (!assistantEvent || assistantEvent.type !== "assistant_message") {
73→      throw new Error("Missing assistant_message event");
74→    }
