 60→async function handleCreateWorkspace(deps: ServerDependencies, request: Request): Promise<Response> {
 61→  const startedAt = performance.now();
 62→  logInfo("workspace.create.started", "Workspace creation started");
 63→
 64→  let body: unknown;
 65→  try {
 66→    body = await request.json();
 67→  } catch {
 68→    return jsonError("Request body must be valid JSON", 400);
 69→  }
 70→
 71→  const parsed = parseCreateWorkspaceRequest(body);
 72→  if (!parsed.ok) {
 73→    return jsonError(parsed.error, 400);
 74→  }
 75→
 76→  logDebug("http.request.validated", "Workspace request validated");
 77→
 78→  const now = new Date();
 79→  const workspaceId = randomUUID();
 80→  const conversationId = randomUUID();
 81→  const ownerId = randomUUID();
 82→
 83→  const workspaceRecord = new RecordId("workspace", workspaceId);
 84→  const conversationRecord = new RecordId("conversation", conversationId);
 85→  const ownerRecord = new RecordId("person", ownerId);
 86→  const starterMessageRecord = new RecordId("message", randomUUID());
 87→  const hasDescription = parsed.data.description !== undefined;
 88→
 89→  const starterSuggestions = hasDescription
 90→    ? [
 91→        "Describe your first project",
 92→        "Share the biggest current bottleneck",
 93→        "Upload a plan or spec to extract",
 94→      ]
 95→    : [
 96→        "Describe your business and goals",
 97→        "Share the biggest current bottleneck",
 98→        "Upload a plan or spec to extract",
 99→      ];
100→
101→  const starterMessage = hasDescription
102→    ? [
103→        `Hey ${parsed.data.ownerDisplayName}!`,
104→        `Got it — I'll help you organize ${parsed.data.name}.`,
105→        "What are the main projects or product areas you want to track?",
106→        "You can also drop in a document (plan, spec, PRD) and I'll extract everything from it.",
107→      ].join(" ")
108→    : [
109→        `Hey ${parsed.data.ownerDisplayName}!`,
110→        "I'm ready to help you build out your workspace.",
111→        "Tell me about what you're working on - what's the main project or business you want to track here?",
112→        "If you have an existing document (like a plan or spec), you can drop it in and I'll extract everything from it.",
113→      ].join(" ");
114→
115→  const transaction = await deps.surreal.beginTransaction();
116→  try {
117→    await transaction.create(workspaceRecord).content({
118→      name: parsed.data.name,
119→      ...(parsed.data.description ? { description: parsed.data.description } : {}),
120→      status: "active",
121→      onboarding_complete: false,
122→      onboarding_turn_count: 0,
123→      onboarding_summary_pending: false,
124→      onboarding_started_at: now,
125→      created_at: now,
126→      updated_at: now,
127→    });
128→
129→    const ownerEmbedding = await createEmbeddingVector(
130→      deps.embeddingModel,
131→      parsed.data.ownerDisplayName,
132→      deps.config.embeddingDimension,
133→    );
134→    await transaction.create(ownerRecord).content({
135→      name: parsed.data.ownerDisplayName,
136→      contact_email: parsed.data.ownerEmail,
137→      ...(ownerEmbedding ? { embedding: ownerEmbedding } : {}),
138→      created_at: now,
139→      updated_at: now,
140→    });
141→
142→    await transaction.relate(ownerRecord, new RecordId("member_of", randomUUID()), workspaceRecord, {
143→      role: "owner",
144→      added_at: now,
145→    }).output("after");
146→
147→    await transaction.create(conversationRecord).content({
148→      createdAt: now,
149→      updatedAt: now,
150→      workspace: workspaceRecord,
151→      source: "onboarding",
152→      title: "Onboarding",
153→      title_source: "message",
154→    });
155→
156→    await transaction.create(starterMessageRecord).content({
157→      conversation: conversationRecord,
158→      role: "assistant",
159→      text: starterMessage,
160→      suggestions: starterSuggestions,
161→      createdAt: now,
162→    });
163→
164→    await transaction.commit();
165→  } catch (error) {
166→    await transaction.cancel();
167→    logError("workspace.create.failed", "Workspace creation failed", error, {
168→      workspaceId,
169→      conversationId,
170→    });
171→    const errorText = error instanceof Error ? error.message : "workspace creation failed";
172→    return jsonError(errorText, 500);
173→  }
174→
175→  const response: CreateWorkspaceResponse = {
176→    workspaceId,
177→    workspaceName: parsed.data.name,
178→    conversationId,
179→    onboardingComplete: false,
180→  };
181→
182→  logInfo("workspace.create.completed", "Workspace creation completed", {
183→    workspaceId,
184→    conversationId,
185→    durationMs: elapsedMs(startedAt),
186→  });
187→
188→  return jsonResponse(response, 200);
189→}
