191→async function handleWorkspaceBootstrap(deps: ServerDependencies, workspaceId: string): Promise<Response> {
192→  const startedAt = performance.now();
193→  logInfo("workspace.bootstrap.started", "Workspace bootstrap started", { workspaceId });
194→
195→  try {
196→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
197→    const workspace = await deps.surreal.select<WorkspaceRow>(workspaceRecord);
198→    if (!workspace) {
199→      throw new HttpError(404, `workspace not found: ${workspaceId}`);
200→    }
201→
202→    const conversationRecord = await resolveWorkspaceBootstrapConversation(deps, workspaceRecord);
203→    const conversationId = conversationRecord.id as string;
204→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
205→
206→    const messages = rawMessages.map((row) => ({
207→      id: row.id,
208→      role: row.role,
209→      text: row.text,
210→      createdAt: toIsoString(row.createdAt),
211→      ...(row.suggestions && row.suggestions.length > 0 ? { suggestions: row.suggestions } : {}),
212→      ...(row.inherited ? { inherited: true } : {}),
213→    } satisfies WorkspaceBootstrapMessage));
214→
215→    const seeds = await loadWorkspaceSeeds(deps, workspaceRecord, 40);
216→    const onboardingState = toOnboardingState(workspace);
217→    const sidebar = await buildWorkspaceConversationSidebar(deps.surreal, workspaceRecord);
218→
219→    const payload: WorkspaceBootstrapResponse = {
220→      workspaceId: workspace.id.id as string,
221→      workspaceName: workspace.name,
222→      ...(workspace.description ? { workspaceDescription: workspace.description } : {}),
223→      onboardingComplete: workspace.onboarding_complete,
224→      onboardingState,
225→      conversationId: conversationRecord.id as string,
226→      messages,
227→      seeds,
228→      sidebar,
229→    };
230→
231→    logInfo("workspace.bootstrap.completed", "Workspace bootstrap completed", {
232→      workspaceId,
233→      conversationId: conversationRecord.id as string,
234→      messageCount: messages.length,
235→      seedCount: seeds.length,
236→      durationMs: elapsedMs(startedAt),
237→    });
238→
239→    return jsonResponse(payload, 200);
240→  } catch (error) {
241→    if (error instanceof HttpError) {
242→      logWarn("workspace.bootstrap.http_error", "Workspace bootstrap failed with client-facing error", {
243→        workspaceId,
244→        statusCode: error.status,
245→      });
246→      return jsonError(error.message, error.status);
247→    }
248→
249→    logError("workspace.bootstrap.failed", "Workspace bootstrap failed", error, { workspaceId });
250→    const errorText = error instanceof Error ? error.message : "workspace bootstrap failed";
251→    return jsonError(errorText, 500);
252→  }
253→}
