409→async function handleWorkspaceConversation(
410→  deps: ServerDependencies,
411→  workspaceId: string,
412→  conversationId: string,
413→): Promise<Response> {
414→  const startedAt = performance.now();
415→  logInfo("workspace.conversation.started", "Workspace conversation request started", {
416→    workspaceId,
417→    conversationId,
418→  });
419→
420→  try {
421→    const workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
422→    const conversationRecord = new RecordId("conversation", conversationId);
423→    const conversation = await deps.surreal.select<{
424→      id: RecordId<"conversation", string>;
425→      workspace: RecordId<"workspace", string>;
426→      discusses?: RecordId;
427→    }>(conversationRecord);
428→
429→    if (!conversation) {
430→      throw new HttpError(404, `conversation not found: ${conversationId}`);
431→    }
432→
433→    if ((conversation.workspace.id as string) !== (workspaceRecord.id as string)) {
434→      throw new HttpError(400, "conversation does not belong to workspace");
435→    }
436→
437→    const rawMessages = await loadMessagesWithInheritance(deps.surreal, conversationId, 80);
438→
439→    const messages = rawMessages.map((row) => ({
440→      id: row.id,
441→      role: row.role,
442→      text: row.text,
