458→          ...(entityRow && typeof entityRow.status === "string" ? { status: entityRow.status } : {}),
459→        };
460→      }
461→    }
462→
463→    const payload: WorkspaceConversationResponse = {
464→      conversationId,
465→      messages,
466→      ...(discussEntity ? { discussEntity } : {}),
467→    };
468→
469→    logInfo("workspace.conversation.completed", "Workspace conversation request completed", {
470→      workspaceId,
471→      conversationId,
472→      messageCount: messages.length,
473→      durationMs: elapsedMs(startedAt),
474→    });
475→
476→    return jsonResponse(payload, 200);
477→  } catch (error) {
478→    if (error instanceof HttpError) {
479→      logWarn("workspace.conversation.http_error", "Workspace conversation failed with client-facing error", {
480→        workspaceId,
481→        conversationId,
482→        statusCode: error.status,
483→      });
484→      return jsonError(error.message, error.status);
485→    }
486→
487→    logError("workspace.conversation.failed", "Workspace conversation request failed", error, {
488→      workspaceId,
489→      conversationId,
490→    });
491→    const errorText = error instanceof Error ? error.message : "workspace conversation failed";
492→    return jsonError(errorText, 500);
493→  }
