 60→export async function parseIncomingMessageRequest(
 61→  request: Request,
 62→): Promise<{ ok: true; data: ParsedIncomingMessage } | { ok: false; error: string }> {
 63→  const contentType = request.headers.get("content-type") ?? "";
 64→
 65→  if (contentType.includes("multipart/form-data")) {
 66→    const formData = await request.formData();
 67→
 68→    const clientMessageIdValue = formData.get("clientMessageId");
 69→    const workspaceIdValue = formData.get("workspaceId");
 70→    const conversationIdValue = formData.get("conversationId");
 71→    const textValue = formData.get("text");
 72→    const onboardingActionValue = formData.get("onboardingAction");
 73→    const discussEntityIdValue = formData.get("discussEntityId");
 74→
 75→    if (typeof clientMessageIdValue !== "string" || clientMessageIdValue.trim().length === 0) {
 76→      return { ok: false, error: "clientMessageId is required" };
 77→    }
 78→
 79→    if (typeof workspaceIdValue !== "string" || workspaceIdValue.trim().length === 0) {
 80→      return { ok: false, error: "workspaceId is required" };
 81→    }
 82→
