  5→export function SignInPage() {
  6→  const { data: session, isPending } = useSession();
  7→  const navigate = useNavigate();
  8→  const search = useSearch({ strict: false }) as Record<string, string>;
  9→
 10→  const [mode, setMode] = useState<"signin" | "signup">("signin");
 11→  const [email, setEmail] = useState("");
 12→  const [password, setPassword] = useState("");
 13→  const [name, setName] = useState("");
 14→  const [error, setError] = useState("");
 15→  const [loading, setLoading] = useState(false);
 16→
 17→  // If already authenticated, redirect away
 18→  if (!isPending && session) {
 19→    const redirectTo = search.redirectTo ?? "/";
 20→    void navigate({ to: redirectTo });
 21→    return undefined;
 22→  }
 23→
 24→  // Build the URL to resume the OAuth flow after login.
 25→  // better-auth passes the original OAuth query params (signed) to the login page.
 26→  // After login we redirect back to /api/auth/oauth2/authorize with those params.
 27→  function getPostLoginRedirect(): string {
 28→    const { redirectTo, ...oauthParams } = search;
 29→
 30→    // If there's an explicit redirectTo, use it
 31→    if (redirectTo) return redirectTo;
 32→
 33→    // If OAuth params are present (client_id, sig, etc.), resume the authorize flow
 34→    if (oauthParams.client_id || oauthParams.sig) {
 35→      const params = new URLSearchParams(oauthParams);
 36→      return `/api/auth/oauth2/authorize?${params.toString()}`;
 37→    }
 38→
 39→    return "/";
 40→  }
 41→
 42→  async function handleSubmit(e: React.FormEvent) {
 43→    e.preventDefault();
 44→    setError("");
 45→    setLoading(true);
 46→
 47→    try {
 48→      if (mode === "signup") {
 49→        const result = await signUp.email({ email, password, name });
 50→        if (result.error) {
 51→          setError(result.error.message ?? "Sign up failed");
 52→          setLoading(false);
 53→          return;
 54→        }
 55→      } else {
 56→        const result = await signIn.email({ email, password });
 57→        if (result.error) {
 58→          setError(result.error.message ?? "Invalid credentials");
 59→          setLoading(false);
 60→          return;
 61→        }
 62→      }
 63→
 64→      // Redirect after successful auth
 65→      window.location.href = getPostLoginRedirect();
 66→    } catch (err) {
 67→      setError(err instanceof Error ? err.message : "Authentication failed");
 68→      setLoading(false);
 69→    }
 70→  }
 71→
 72→  async function handleGitHub() {
 73→    setError("");
 74→    await signIn.social({
 75→      provider: "github",
 76→      callbackURL: getPostLoginRedirect(),
 77→    });
 78→  }
 79→
 80→  if (isPending) {
 81→    return (
 82→      <div className="sign-in-page">
 83→        <div className="sign-in-card">
 84→          <p className="sign-in-loading">Loading...</p>
 85→        </div>
 86→      </div>
 87→    );
 88→  }
 89→
 90→  return (
 91→    <div className="sign-in-page">
 92→      <div className="sign-in-card">
 93→        <h1 className="sign-in-title">Brain</h1>
 94→        <p className="sign-in-subtitle">
 95→          {mode === "signin" ? "Sign in to your workspace" : "Create an account"}
 96→        </p>
 97→
 98→        <form onSubmit={handleSubmit} className="sign-in-form">
 99→          {mode === "signup" && (
100→            <input
101→              type="text"
102→              placeholder="Name"
103→              value={name}
104→              onChange={(e) => setName(e.target.value)}
105→              className="sign-in-input"
106→              required
107→            />
108→          )}
109→          <input
110→            type="email"
111→            placeholder="Email"
112→            value={email}
113→            onChange={(e) => setEmail(e.target.value)}
114→            className="sign-in-input"
115→            required
116→          />
117→          <input
118→            type="password"
119→            placeholder="Password"
120→            value={password}
121→            onChange={(e) => setPassword(e.target.value)}
122→            className="sign-in-input"
123→            required
124→            minLength={8}
125→          />
126→
127→          {error && <p className="sign-in-error">{error}</p>}
128→
129→          <button type="submit" className="sign-in-button" disabled={loading}>
130→            {loading ? "..." : mode === "signin" ? "Sign in" : "Create account"}
131→          </button>
132→        </form>
133→
134→        <div className="sign-in-divider">
135→          <span>or</span>
136→        </div>
137→
138→        <button type="button" className="sign-in-button sign-in-github" onClick={handleGitHub}>
139→          Sign in with GitHub
140→        </button>
141→
142→        <p className="sign-in-switch">
143→          {mode === "signin" ? (
144→            <>
145→              No account?{" "}
146→              <button type="button" onClick={() => { setMode("signup"); setError(""); }}>
147→                Create one
148→              </button>
149→            </>
150→          ) : (
151→            <>
152→              Already have an account?{" "}
153→              <button type="button" onClick={() => { setMode("signin"); setError(""); }}>
154→                Sign in
155→              </button>
156→            </>
157→          )}
158→        </p>
159→      </div>
160→    </div>
161→  );
162→}
