  1→import { FormEvent, useEffect, useState } from "react";
  2→import type { UIMessage } from "ai";
  3→import type {
  4→  CreateWorkspaceRequest,
  5→  CreateWorkspaceResponse,
  6→  WorkspaceBootstrapMessage,
  7→  WorkspaceBootstrapResponse,
  8→} from "../../shared/contracts";
  9→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 10→
 11→const ACTIVE_WORKSPACE_STORAGE_KEY = "brain.activeWorkspaceId";
 12→
 13→type UseWorkspaceReturn = {
 14→  isReady: boolean;
 15→  isBootstrapping: boolean;
 16→  isCreatingWorkspace: boolean;
 17→  errorMessage?: string;
 18→  createWorkspaceName: string;
 19→  createOwnerName: string;
 20→  createOwnerEmail: string;
 21→  createWorkspaceDescription: string;
 22→  canCreateWorkspace: boolean;
 23→  setCreateWorkspaceName: (name: string) => void;
 24→  setCreateOwnerName: (name: string) => void;
 25→  setCreateOwnerEmail: (email: string) => void;
 26→  setCreateWorkspaceDescription: (description: string) => void;
 27→  onCreateWorkspace: (event: FormEvent<HTMLFormElement>) => void;
 28→};
 29→
 30→function bootstrapMessagesToUIMessages(messages: WorkspaceBootstrapMessage[]): UIMessage[] {
 31→  return messages.map((m) => ({
 32→    id: m.id,
 33→    role: m.role,
 34→    parts: [{ type: "text" as const, text: m.text }],
 35→    createdAt: new Date(m.createdAt),
 36→  }));
 37→}
 38→
 39→function parseBootstrapMessages(payload: WorkspaceBootstrapResponse): BootstrapPayload {
 40→  return { messages: bootstrapMessagesToUIMessages(payload.messages) };
 41→}
 42→
 43→export { parseBootstrapMessages, ACTIVE_WORKSPACE_STORAGE_KEY };
 44→
 45→export function useWorkspace(): UseWorkspaceReturn {
 46→  const store = useWorkspaceState();
 47→  const [createWorkspaceName, setCreateWorkspaceName] = useState("");
 48→  const [createOwnerName, setCreateOwnerName] = useState("");
 49→  const [createOwnerEmail, setCreateOwnerEmail] = useState("");
 50→  const [createWorkspaceDescription, setCreateWorkspaceDescription] = useState("");
 51→  const [isCreatingWorkspace, setIsCreatingWorkspace] = useState(false);
 52→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 53→
 54→  const canCreateWorkspace =
 55→    createWorkspaceName.trim().length > 0 && createOwnerName.trim().length > 0 && createOwnerEmail.trim().length > 0;
 56→
 57→  useEffect(() => {
 58→    const existingWorkspaceId = window.localStorage.getItem(ACTIVE_WORKSPACE_STORAGE_KEY);
 59→    if (!existingWorkspaceId) {
 60→      return;
 61→    }
 62→
 63→    void bootstrapWorkspace(existingWorkspaceId);
 64→  }, []);
 65→
 66→  async function bootstrapWorkspace(workspaceId: string) {
 67→    store.setIsBootstrapping(true);
 68→    setErrorMessage(undefined);
 69→
 70→    let response: Response;
 71→    try {
 72→      response = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/bootstrap`);
 73→    } catch (error) {
 74→      const messageText = error instanceof Error ? error.message : "Network error";
 75→      setErrorMessage(messageText);
 76→      store.setIsBootstrapping(false);
 77→      return;
 78→    }
 79→
 80→    if (!response.ok) {
 81→      if (response.status === 404) {
 82→        window.localStorage.removeItem(ACTIVE_WORKSPACE_STORAGE_KEY);
 83→        store.clearWorkspace();
 84→      }
 85→      const body = await response.text();
 86→      setErrorMessage(body);
 87→      store.setIsBootstrapping(false);
 88→      return;
 89→    }
 90→
 91→    const payload = (await response.json()) as WorkspaceBootstrapResponse;
 92→    applyBootstrapPayload(payload);
 93→    store.setIsBootstrapping(false);
 94→  }
 95→
 96→  function applyBootstrapPayload(payload: WorkspaceBootstrapResponse) {
 97→    const parsed = parseBootstrapMessages(payload);
 98→
 99→    store.setSeedItems(payload.seeds);
100→    store.setSidebar(payload.sidebar);
101→    store.setBootstrapPayload(parsed);
102→    store.applyWorkspace({
103→      id: payload.workspaceId,
104→      name: payload.workspaceName,
105→      onboardingComplete: payload.onboardingComplete,
106→      onboardingState: payload.onboardingState,
107→      conversationId: payload.conversationId,
108→    });
109→  }
110→
111→  async function onCreateWorkspace(event: FormEvent<HTMLFormElement>) {
112→    event.preventDefault();
113→
114→    const name = createWorkspaceName.trim();
115→    const ownerDisplayName = createOwnerName.trim();
116→    const ownerEmail = createOwnerEmail.trim();
117→    if (isCreatingWorkspace) {
118→      return;
119→    }
120→
121→    if (!name || !ownerDisplayName || !ownerEmail) {
122→      setErrorMessage("Workspace name, owner display name, and email are required");
123→      return;
124→    }
125→
126→    setErrorMessage(undefined);
127→    setIsCreatingWorkspace(true);
128→
129→    const description = createWorkspaceDescription.trim();
130→    const requestBody: CreateWorkspaceRequest = {
131→      name,
132→      ownerDisplayName,
133→      ownerEmail,
134→      ...(description.length > 0 ? { description } : {}),
135→    };
136→
137→    try {
138→      const response = await fetch("/api/workspaces", {
139→        method: "POST",
140→        headers: {
141→          "Content-Type": "application/json",
142→        },
143→        body: JSON.stringify(requestBody),
144→      });
145→
146→      if (!response.ok) {
147→        const body = await response.text();
148→        setErrorMessage(body);
149→        return;
150→      }
151→
152→      const payload = (await response.json()) as Partial<CreateWorkspaceResponse>;
153→      if (typeof payload.workspaceId !== "string" || payload.workspaceId.trim().length === 0) {
154→        throw new Error("create workspace response is missing workspaceId");
155→      }
156→
157→      window.localStorage.setItem(ACTIVE_WORKSPACE_STORAGE_KEY, payload.workspaceId);
158→      await bootstrapWorkspace(payload.workspaceId);
159→      setCreateWorkspaceName("");
160→      setCreateOwnerName("");
161→      setCreateOwnerEmail("");
162→      setCreateWorkspaceDescription("");
163→    } catch (error) {
164→      const messageText = error instanceof Error ? error.message : "Workspace creation failed";
165→      setErrorMessage(messageText);
166→    } finally {
167→      setIsCreatingWorkspace(false);
168→    }
169→  }
170→
171→  return {
172→    isReady: store.workspaceId !== undefined && !store.isBootstrapping,
173→    isBootstrapping: store.isBootstrapping,
174→    isCreatingWorkspace,
175→    errorMessage,
176→    createWorkspaceName,
177→    createOwnerName,
178→    createOwnerEmail,
179→    createWorkspaceDescription,
180→    canCreateWorkspace,
181→    setCreateWorkspaceName,
182→    setCreateOwnerName,
183→    setCreateOwnerEmail,
184→    setCreateWorkspaceDescription,
185→    onCreateWorkspace,
186→  };
187→}
