  1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
  2→import { useNavigate } from "@tanstack/react-router";
  3→import { useChat, type UseChatHelpers } from "@ai-sdk/react";
  4→import { DefaultChatTransport, type UIMessage } from "ai";
  5→import type {
  6→  BranchConversationResponse,
  7→  DiscussEntitySummary,
  8→  OnboardingAction,
  9→  OnboardingState,
 10→  WorkspaceBootstrapMessage,
 11→  WorkspaceConversationResponse,
 12→} from "../../shared/contracts";
 13→import { useWorkspaceState, type BootstrapPayload } from "../stores/workspace-state";
 14→import { useViewState } from "../stores/view-state";
 15→
 16→type ChatMessageMetadata = {
 17→  onboardingState?: OnboardingState;
 18→  conversationId?: string;
 19→};
 20→
 21→type ChatUIMessage = UIMessage<ChatMessageMetadata>;
 22→
 23→export type UseChatSessionReturn = {
 24→  messages: ChatUIMessage[];
 25→  status: UseChatHelpers<ChatUIMessage>["status"];
 26→  isLoading: boolean;
 27→  errorMessage?: string;
 28→  activeConversationId?: string;
 29→  branchingFromId?: string;
 30→  discussEntity?: DiscussEntitySummary;
 31→  conversationDiscussEntity?: DiscussEntitySummary;
 32→  sendMessage: (text: string, options?: { onboardingAction?: OnboardingAction }) => void;
 33→  stopMessage: () => void;
 34→  newConversation: () => void;
 35→  resetChat: () => void;
 36→  selectConversation: (conversationId: string) => void;
 37→  branchFromMessage: (messageId: string) => Promise<void>;
 38→  setErrorMessage: (message: string | undefined) => void;
 39→  refreshSidebar: (workspaceId: string) => Promise<void>;
 40→};
 41→
 42→function bootstrapMessagesToUIMessages(messages: WorkspaceBootstrapMessage[]): ChatUIMessage[] {
 43→  return messages.map((m) => ({
 44→    id: m.id,
 45→    role: m.role,
 46→    parts: [{ type: "text" as const, text: m.text }],
 47→    createdAt: new Date(m.createdAt),
 48→  }));
 49→}
 50→
 51→export function useChatSession(routeConversationId?: string): UseChatSessionReturn {
 52→  const store = useWorkspaceState();
 53→  const workspaceId = store.workspaceId;
 54→  const bootstrapPayload = store.bootstrapPayload;
 55→  const navigate = useNavigate();
 56→
 57→  const [activeConversationId, setActiveConversationId] = useState<string | undefined>();
 58→  const [errorMessage, setErrorMessage] = useState<string | undefined>();
 59→  const [branchingFromId, setBranchingFromId] = useState<string | undefined>();
 60→  const [conversationDiscussEntity, setConversationDiscussEntity] = useState<
 61→    DiscussEntitySummary | undefined
 62→  >();
 63→
 64→  const discussEntity = useViewState((s) => s.discussEntity);
 65→  const clearDiscussEntity = useViewState((s) => s.clearDiscussEntity);
 66→
 67→  // Dynamic body refs — these are read by the transport body function
 68→  const conversationIdRef = useRef<string | undefined>(undefined);
 69→  const onboardingActionRef = useRef<OnboardingAction | undefined>(undefined);
 70→  const discussEntityIdRef = useRef<string | undefined>(undefined);
 71→
 72→  // Keep conversationId ref in sync
 73→  useEffect(() => {
 74→    conversationIdRef.current = activeConversationId;
 75→  }, [activeConversationId]);
 76→
 77→  // Keep discuss entity ref in sync
 78→  useEffect(() => {
 79→    discussEntityIdRef.current = discussEntity?.id;
 80→  }, [discussEntity]);
 81→
 82→  const transport = useMemo(
 83→    () =>
 84→      new DefaultChatTransport({
 85→        api: "/api/chat",
 86→        body: () => ({
 87→          workspaceId,
 88→          ...(conversationIdRef.current ? { conversationId: conversationIdRef.current } : {}),
 89→          ...(onboardingActionRef.current
 90→            ? { onboardingAction: onboardingActionRef.current }
 91→            : {}),
 92→          ...(discussEntityIdRef.current
 93→            ? { discussEntityId: discussEntityIdRef.current }
 94→            : {}),
 95→        }),
 96→      }),
 97→    [workspaceId],
 98→  );
 99→
100→  const chat = useChat<ChatUIMessage>({
101→    transport,
102→    onFinish: ({ message }) => {
103→      const metadata = message.metadata;
104→      if (metadata?.conversationId && !conversationIdRef.current) {
105→        setActiveConversationId(metadata.conversationId);
106→        conversationIdRef.current = metadata.conversationId;
107→        void navigate({
108→          to: "/chat/$conversationId",
109→          params: { conversationId: metadata.conversationId },
110→          replace: true,
111→        });
112→        if (discussEntity) {
113→          clearDiscussEntity();
114→        }
115→      }
116→      if (metadata?.onboardingState) {
117→        store.setOnboardingState(metadata.onboardingState);
118→      }
119→
120→      // Refresh sidebar
121→      if (workspaceId) {
122→        void refreshSidebar(workspaceId);
123→      }
124→    },
125→    onError: (error) => {
126→      setErrorMessage(error.message);
127→    },
128→  });
129→
130→  const isLoading = chat.status === "streaming" || chat.status === "submitted";
131→
132→  // Apply bootstrap payload when it arrives — only load messages when on /chat/:id
133→  const appliedBootstrapRef = useRef<BootstrapPayload | undefined>(undefined);
134→  useEffect(() => {
135→    if (!bootstrapPayload || bootstrapPayload === appliedBootstrapRef.current) {
136→      return;
137→    }
138→    appliedBootstrapRef.current = bootstrapPayload;
139→
140→    // On /chat (new conversation), skip loading bootstrap messages
141→    if (!routeConversationId) {
142→      return;
143→    }
144→
145→    chat.setMessages(bootstrapPayload.messages as ChatUIMessage[]);
146→    setActiveConversationId(store.conversationId);
147→    conversationIdRef.current = store.conversationId;
148→  }, [bootstrapPayload, routeConversationId]);
149→
150→  async function refreshSidebar(wsId: string) {
151→    try {
152→      const response = await fetch(`/api/workspaces/${encodeURIComponent(wsId)}/sidebar`);
153→      if (response.ok) {
154→        const payload = await response.json();
155→        store.setSidebar(payload);
156→      }
157→    } catch {
158→      // Sidebar refresh is non-critical
159→    }
160→  }
161→
162→  async function loadConversation(wsId: string, conversationId: string) {
163→    try {
164→      const response = await fetch(
165→        `/api/workspaces/${encodeURIComponent(wsId)}/conversations/${encodeURIComponent(conversationId)}`,
166→      );
167→      if (!response.ok) {
168→        const body = await response.text();
169→        setErrorMessage(body);
170→        void navigate({ to: "/chat", replace: true });
171→        return;
172→      }
173→
174→      const payload = (await response.json()) as WorkspaceConversationResponse;
175→      const uiMessages = bootstrapMessagesToUIMessages(payload.messages) as ChatUIMessage[];
176→      chat.setMessages(uiMessages);
177→
178→      setActiveConversationId(conversationId);
179→      conversationIdRef.current = conversationId;
180→      setConversationDiscussEntity(payload.discussEntity);
181→    } catch (error) {
182→      const messageText = error instanceof Error ? error.message : "Failed to load conversation";
183→      setErrorMessage(messageText);
184→    }
185→  }
186→
187→  const sendMessage = useCallback(
188→    (text: string, options?: { onboardingAction?: OnboardingAction }) => {
189→      if (isLoading || !workspaceId) return;
190→
191→      const trimmed = text.trim();
192→      if (!trimmed) return;
193→
194→      setErrorMessage(undefined);
195→      onboardingActionRef.current = options?.onboardingAction;
196→
197→      chat.sendMessage({ text: trimmed });
198→
199→      // Clear after queueing
200→      onboardingActionRef.current = undefined;
201→    },
202→    [isLoading, workspaceId, chat.sendMessage],
203→  );
204→
205→  function stopMessage() {
206→    chat.stop();
207→  }
208→
209→  function newConversation() {
210→    setActiveConversationId(undefined);
211→    conversationIdRef.current = undefined;
212→    chat.setMessages([]);
213→    setErrorMessage(undefined);
214→    setConversationDiscussEntity(undefined);
215→    clearDiscussEntity();
216→    void navigate({ to: "/chat" });
217→  }
218→
219→  function resetChat() {
220→    setActiveConversationId(undefined);
221→    conversationIdRef.current = undefined;
222→    chat.setMessages([]);
223→    setErrorMessage(undefined);
224→    setConversationDiscussEntity(undefined);
225→  }
226→
227→  function selectConversation(conversationId: string) {
228→    if (conversationId === activeConversationId || isLoading || !workspaceId) {
229→      return;
230→    }
231→    clearDiscussEntity();
232→    void loadConversation(workspaceId, conversationId);
233→  }
234→
235→  async function branchFromMessage(messageId: string) {
236→    if (!workspaceId || !activeConversationId || isLoading) return;
237→
238→    setBranchingFromId(messageId);
239→    try {
240→      const response = await fetch(
241→        `/api/workspaces/${encodeURIComponent(workspaceId)}/conversations/${encodeURIComponent(activeConversationId)}/branch`,
242→        {
243→          method: "POST",
244→          headers: { "Content-Type": "application/json" },
245→          body: JSON.stringify({ messageId }),
246→        },
247→      );
248→
249→      if (!response.ok) {
250→        const body = await response.text();
251→        setErrorMessage(body);
252→        return;
253→      }
254→
255→      const payload = (await response.json()) as BranchConversationResponse;
256→      await loadConversation(workspaceId, payload.conversationId);
257→      void navigate({
258→        to: "/chat/$conversationId",
259→        params: { conversationId: payload.conversationId },
260→      });
261→      await refreshSidebar(workspaceId);
262→    } catch (error) {
263→      const messageText = error instanceof Error ? error.message : "Branch creation failed";
264→      setErrorMessage(messageText);
265→    } finally {
266→      setBranchingFromId(undefined);
267→    }
268→  }
269→
270→  return {
271→    messages: chat.messages,
272→    status: chat.status,
273→    isLoading,
274→    errorMessage,
275→    activeConversationId,
276→    branchingFromId,
277→    discussEntity,
278→    conversationDiscussEntity,
279→    sendMessage,
280→    stopMessage,
281→    newConversation,
282→    resetChat,
283→    selectConversation,
284→    branchFromMessage,
285→    setErrorMessage,
286→    refreshSidebar,
287→  };
288→}
