123→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
124→    method: "POST",
125→    headers: { "Content-Type": "application/json" },
126→    body: JSON.stringify({ name: "Smoke Tester", email, password: "smoke-test-password-123" }),
127→    redirect: "manual",
128→  });
129→
130→  if (!response.ok) {
131→    const body = await response.text();
132→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
133→  }
134→
135→  const setCookie = response.headers.getSetCookie();
136→  if (!setCookie || setCookie.length === 0) {
137→    throw new Error("Sign-up did not return session cookies");
