197→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
198→  const response = await fetch(url, init);
199→  if (!response.ok) {
200→    const body = await response.text();
201→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
202→  }
203→
204→  return (await response.json()) as T;
205→}
