207→async function waitForHealth(url: string, process: ReturnType<typeof Bun.spawn>, timeoutMs: number): Promise<void> {
208→  const start = Date.now();
209→
210→  while (Date.now() - start < timeoutMs) {
211→    if (typeof process.exitCode === "number") {
212→      const stderr = process.stderr ? await new Response(process.stderr).text() : "";
213→      throw new Error(`Smoke server exited early with code ${process.exitCode}\n${stderr}`);
214→    }
215→
216→    try {
217→      const response = await fetch(`${url}/healthz`);
218→      if (response.ok) {
219→        return;
220→      }
221→    } catch {
222→      // Keep polling.
223→    }
224→
225→    await Bun.sleep(200);
226→  }
227→
228→  throw new Error(`Timed out waiting for smoke server health at ${url}/healthz`);
229→}
