231→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
232→  return await Promise.race([
233→    callback(),
234→    new Promise<T>((_, reject) => {
235→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
236→    }),
237→  ]);
238→}
