 32→async function pollForRecord<T>(
 33→  query: () => Promise<T[]>,
 34→  timeoutMs: number,
 35→  intervalMs = 500,
 36→): Promise<T[]> {
 37→  const start = Date.now();
 38→  while (Date.now() - start < timeoutMs) {
 39→    const rows = await query();
 40→    if (rows.length > 0) return rows;
 41→    await Bun.sleep(intervalMs);
 42→  }
 43→  return [];
 44→}
