 28→type AuthedWorkspace = {
 29→  workspaceId: string;
 30→  workspaceRecord: RecordId<"workspace", string>;
 31→  apiKey: string;
 32→};
 33→
 34→async function createWorkspaceWithApiKey(
 35→  baseUrl: string,
 36→  surreal: Surreal,
 37→  name?: string,
 38→): Promise<AuthedWorkspace> {
 39→  const { workspaceId } = await fetchJson<{ workspaceId: string }>(`${baseUrl}/api/workspaces`, {
 40→    method: "POST",
 41→    headers: { "Content-Type": "application/json" },
 42→    body: JSON.stringify({
 43→      name: name ?? `Intent Smoke ${Date.now()}`,
 44→      ownerDisplayName: "Test", ownerEmail: `${Date.now()}-1@smoke.test`,
 45→    }),
 46→  });
 47→
 48→  const workspaceRecord = new RecordId("workspace", workspaceId);
 49→  const apiKey = generateApiKey();
 50→  const hash = await hashApiKey(apiKey);
 51→  await surreal.update(workspaceRecord).merge({
 52→    api_key_hash: hash,
 53→    onboarding_complete: true,
 54→    onboarding_summary_pending: false,
 55→    onboarding_completed_at: new Date(),
 56→  });
 57→
 58→  return { workspaceId, workspaceRecord, apiKey };
 59→}
