 61→async function seedProject(
 62→  surreal: Surreal,
 63→  workspaceRecord: RecordId<"workspace", string>,
 64→  name: string,
 65→): Promise<RecordId<"project", string>> {
 66→  const projectRecord = new RecordId("project", randomUUID());
 67→  await surreal.create(projectRecord).content({
 68→    name,
 69→    status: "active",
 70→    workspace: workspaceRecord,
 71→    created_at: new Date(),
 72→    updated_at: new Date(),
 73→  });
 74→  await surreal
 75→    .relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
 76→      added_at: new Date(),
 77→    })
 78→    .output("after");
 79→  return projectRecord;
 80→}
