 92→    status: "open",
 93→    priority: "medium",
 94→    workspace: workspaceRecord,
 95→    created_at: new Date(),
 96→    updated_at: new Date(),
 97→    ...(embedding ? { embedding } : {}),
 98→  });
 99→  await surreal
100→    .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
101→      added_at: new Date(),
102→    })
103→    .output("after");
