107→async function seedDecision(
108→  surreal: Surreal,
109→  workspaceRecord: RecordId<"workspace", string>,
110→  projectRecord: RecordId<"project", string>,
111→  summary: string,
112→  status: string,
113→  embedding?: number[],
114→): Promise<RecordId<"decision", string>> {
