116→  await surreal.create(decisionRecord).content({
117→    summary,
118→    status,
119→    workspace: workspaceRecord,
120→    created_at: new Date(),
121→    updated_at: new Date(),
122→    ...(embedding ? { embedding } : {}),
123→  });
124→  await surreal
125→    .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
126→      added_at: new Date(),
127→    })
128→    .output("after");
129→  return decisionRecord;
130→}
