 47→async function signUp(baseUrl: string, email: string, name: string): Promise<Record<string, string>> {
 48→  const res = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
 49→    method: "POST",
 50→    headers: { "Content-Type": "application/json" },
 51→    body: JSON.stringify({ email, password: "smoke-test-password-123!", name }),
 52→  });
 53→  if (!res.ok) throw new Error(`Sign up failed: ${res.status} ${await res.text()}`);
 54→  const data = (await res.json()) as { token: string };
 55→  const cookies = res.headers.getSetCookie();
 56→  const sessionCookie = cookies.find((c) => c.startsWith("better-auth.session_token="));
 57→  const sessionToken = sessionCookie
 58→    ? decodeURIComponent(sessionCookie.split("=")[1].split(";")[0])
 59→    : data.token;
 60→  return { Cookie: `better-auth.session_token=${sessionToken}` };
 61→}
